declare @name nvarchar(4000)
if @ct_theo = '2' and exists(select 1 from dmkh where ma_kh = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_kh else ten_kh2 end) from dmkh where ma_kh = @ma
if @ct_theo = '1' and exists(select 1 from dmtk where tk = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_tk else ten_tk2 end) from dmtk where tk = @ma
if @ct_theo = '3' and exists(select 1 from dmnx where ma_nx = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_nx else ten_nx2 end) from dmnx where ma_nx = @ma
if @ct_theo = '4' and exists(select 1 from dmvt where ma_vt = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_vt else ten_vt2 end) from dmvt where ma_vt = @ma
if @ct_theo = '5' and exists(select 1 from dmvv where ma_vv = @ma)
  select @name = rtrim(case when @@language = 'V' then ten_vv else ten_vv2 end) from dmvv where ma_vv = @ma
select 'this._itemName = ''' + replace(replace(isnull(@name, ''), '\', '\\'), '''', '\''') + ''';this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + ''';init$GridQuery$(this);' as message
return




    &XMLWhenReportLoading;
    &XMLWhenReportClosing;





      &DeclareCommandFilter;



        &QueryString;

declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000)
select @queryFormClause = 'left join dmvt b on a.ma_vt = b.ma_vt left join dmkh c on a.ma_kh = c.ma_kh'
select @queryWhereClause = case
  when @ct_theo = '0' then 'a.ma_bp = ''' +  replace(@ma, '''', '''''') + ''''
  when @ct_theo = '1' then 'a.tk_du = ''' +  replace(@ma, '''', '''''') + ''''
  when @ct_theo = '2' then 'a.ma_kh = ''' +  replace(@ma, '''', '''''') + ''''
  when @ct_theo = '3' then 'a.ma_nx = ''' +  replace(@ma, '''', '''''') + ''''
  when @ct_theo = '4' then 'a.ma_vt = ''' +  replace(@ma, '''', '''''') + ''''
  else 'a.ma_vv = ''' +  replace(@ma, '''', '''''') + ''''
end

select @queryWhereClause = @queryWhereClause + ' and ' + case
  when @nh_theo = '0' then 'a.ma_bp = ''' +  replace(@ma2, '''', '''''') + ''''
  when @nh_theo = '1' then 'a.tk_du = ''' +  replace(@ma2, '''', '''''') + ''''
  when @nh_theo = '2' then 'a.ma_kh = ''' +  replace(@ma2, '''', '''''') + ''''
  when @nh_theo = '3' then 'a.ma_nx = ''' +  replace(@ma2, '''', '''''') + ''''
  when @nh_theo = '4' then 'a.ma_vt = ''' +  replace(@ma2, '''', '''''') + ''''
  else 'a.ma_vv = ''' +  replace(@ma2, '''', '''''') + ''''
end

if @so_ct1 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct >= ''' + dbo.ff_PadL(replace(rtrim(@so_ct1), '''', ''''''), @maxLength) + ''''
if @so_ct2 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct <= ''' + dbo.ff_PadL(replace(rtrim(@so_ct2), '''', ''''''), @maxLength) + ''''
if @ma_kho <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_kho like ''' + replace(rtrim(@ma_kho), '''', '''''') + '%'''
if @tk_vt <> '' select @queryWhereClause = @queryWhereClause + ' and a.tk_vt like ''' + replace(rtrim(@tk_vt), '''', '''''') + '%'''
if @ma_hd <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_hd like ''' + replace(rtrim(@ma_hd), '''', '''''') + '%'''

if @ct_theo <> '0' and @nh_theo <> '0' begin
  if @ma_bp <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_bp like ''' + replace(rtrim(@ma_bp), '''', '''''') + '%'''
end
if @ct_theo <> '2' and @nh_theo <> '2' begin
  if @ma_kh <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_kh like ''' + replace(rtrim(@ma_kh), '''', '''''') + '%'''
  if @nh_kh1 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_kh1 like ''' + replace(rtrim(@nh_kh1), '''', '''''') + '%'''
  if @nh_kh2 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_kh2 like ''' + replace(rtrim(@nh_kh2), '''', '''''') + '%'''
  if @nh_kh3 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_kh3 like ''' + replace(rtrim(@nh_kh3), '''', '''''') + '%'''
end
if @ct_theo <> '3' and @nh_theo <> '3' begin
  if @ma_nx <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_nx like ''' + replace(rtrim(@ma_nx), '''', '''''') + '%'''
end
if @ct_theo <> '4' and @nh_theo <> '4' begin
  if @ma_vt <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_vt like ''' + replace(rtrim(@ma_vt), '''', '''''') + '%'''
  if @ma_loai_vt <> '' select @queryWhereClause = @queryWhereClause + ' and b.loai_vt like ''' + replace(rtrim(@ma_loai_vt), '''', '''''') + '%'''
  if @nh_vt1 <> '' select @queryWhereClause = @queryWhereClause + ' and b.nh_vt1 like ''' + replace(rtrim(@nh_vt1), '''', '''''') + '%'''
  if @nh_vt2 <> '' select @queryWhereClause = @queryWhereClause + ' and b.nh_vt2 like ''' + replace(rtrim(@nh_vt2), '''', '''''') + '%'''
  if @nh_vt3 <> '' select @queryWhereClause = @queryWhereClause + ' and b.nh_vt3 like ''' + replace(rtrim(@nh_vt3), '''', '''''') + '%'''
end
if @ct_theo <> '5' and @nh_theo <> '5' begin
  if @ma_vv <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_vv like ''' + replace(rtrim(@ma_vv), '''', '''''') + '%'''
end
if @tinh_ps = '0' select @queryWhereClause = @queryWhereClause + ' and a.ct_dc <> 1'
select @queryWhereClause = @queryWhereClause + ' and a.nxt = 2'
exec rs_GetTransactionKey @ds_ma_ct, @transactionList, 1, 'rptIssuingReportByTwoCriteria', '@@sysDatabaseName', 'a.', @queryWhereClause output
&DynamicFieldGridQueryWhereClause;

